INSERT INTO ui_translations (key, lang, value, updated_at) VALUES
  ('about_intro_title', 'en', 'About Aliolo', CURRENT_TIMESTAMP),
  ('about_intro_desc', 'en', 'Aliolo is a visual learning app built around simple study flows, flexible content organization, and steady progress over time.', CURRENT_TIMESTAMP),
  ('about_intro_start_title', 'en', 'How to Start', CURRENT_TIMESTAMP),
  ('about_intro_start_desc', 'en', 'Begin on the dashboard, choose a pillar, open a subject, and start with Learn. Save useful content to favorites so it is easier to revisit later.', CURRENT_TIMESTAMP),
  ('about_intro_audience_title', 'en', 'Who It Is For', CURRENT_TIMESTAMP),
  ('about_intro_audience_desc', 'en', 'Aliolo supports learners who want structured review, parents and teachers who need approachable study content, and creators who organize and publish their own learning materials.', CURRENT_TIMESTAMP),
  ('about_learn_title', 'en', 'How You Learn', CURRENT_TIMESTAMP),
  ('about_learn_modes_title', 'en', 'Learn and Test', CURRENT_TIMESTAMP),
  ('about_learn_modes_desc', 'en', 'Use Learn to build recognition and confidence, then switch to Test when you want stricter recall and faster review.', CURRENT_TIMESTAMP),
  ('about_learn_language_title', 'en', 'Language and Mode Flexibility', CURRENT_TIMESTAMP),
  ('about_learn_language_desc', 'en', 'You can study content in different languages and adjust session settings in your profile to match your pace and current goals.', CURRENT_TIMESTAMP),
  ('about_learn_media_title', 'en', 'Media Support', CURRENT_TIMESTAMP),
  ('about_learn_media_desc', 'en', 'Images, audio, and video can support recognition, pronunciation, and context when they are available in the learning content.', CURRENT_TIMESTAMP),
  ('about_learn_discovery_title', 'en', 'Discovery and Filtering', CURRENT_TIMESTAMP),
  ('about_learn_discovery_desc', 'en', 'Search, age filters, and source filters such as favorites, mine, and public library help you find the right content quickly.', CURRENT_TIMESTAMP),
  ('about_organize_title', 'en', 'How Content Is Organized', CURRENT_TIMESTAMP),
  ('about_organize_subjects_title', 'en', 'Subjects', CURRENT_TIMESTAMP),
  ('about_organize_subjects_desc', 'en', 'Subjects are the main unit of study. They hold the cards you open in Learn and Test sessions.', CURRENT_TIMESTAMP),
  ('about_organize_folders_title', 'en', 'Folders', CURRENT_TIMESTAMP),
  ('about_organize_folders_desc', 'en', 'Folders group related subjects inside a pillar so larger content sets stay manageable.', CURRENT_TIMESTAMP),
  ('about_organize_collections_title', 'en', 'Collections', CURRENT_TIMESTAMP),
  ('about_organize_collections_desc', 'en', 'Collections combine multiple subjects into one study flow, which is useful for mixed review and curated sets.', CURRENT_TIMESTAMP),
  ('about_organize_creation_title', 'en', 'Ownership and Visibility', CURRENT_TIMESTAMP),
  ('about_organize_creation_desc', 'en', 'Creators can organize their own content, keep it private while working, or expose it through the public library when it is ready.', CURRENT_TIMESTAMP),
  ('about_progress_title', 'en', 'Progress, Friends, and Leaderboard', CURRENT_TIMESTAMP),
  ('about_progress_xp_title', 'en', 'XP and Streaks', CURRENT_TIMESTAMP),
  ('about_progress_xp_desc', 'en', 'Aliolo tracks total XP, current streak, and max streak so progress feels visible across short and long study periods.', CURRENT_TIMESTAMP),
  ('about_progress_goals_title', 'en', 'Daily Goals and Session Settings', CURRENT_TIMESTAMP),
  ('about_progress_goals_desc', 'en', 'Your profile lets you tune daily goal targets, learn session size, test session size, and number of answers.', CURRENT_TIMESTAMP),
  ('about_progress_social_title', 'en', 'Friends and Leaderboard', CURRENT_TIMESTAMP),
  ('about_progress_social_desc', 'en', 'Friends and leaderboard features make progress social without changing the core learning flow.', CURRENT_TIMESTAMP),
  ('about_support_title', 'en', 'Settings, Feedback, and Support', CURRENT_TIMESTAMP),
  ('about_support_settings_title', 'en', 'Personalization', CURRENT_TIMESTAMP),
  ('about_support_settings_desc', 'en', 'UI language, theme mode, theme color, sound, sidebar placement, and documentation visibility can all be adjusted from settings.', CURRENT_TIMESTAMP),
  ('about_support_docs_title', 'en', 'Documentation', CURRENT_TIMESTAMP),
  ('about_support_docs_desc', 'en', 'The in-app documentation page explains how the dashboard, study flows, and creator tools work today.', CURRENT_TIMESTAMP),
  ('about_support_feedback_title', 'en', 'Feedback and Reporting', CURRENT_TIMESTAMP),
  ('about_support_feedback_desc', 'en', 'Use feedback entry points across the app to report bugs, suggest improvements, or flag specific content issues with context.', CURRENT_TIMESTAMP),
  ('about_support_onboarding_title', 'en', 'Onboarding', CURRENT_TIMESTAMP),
  ('about_support_onboarding_desc', 'en', 'You can revisit onboarding at any time to review the app''s main ideas and setup flow.', CURRENT_TIMESTAMP),
  ('about_support_licenses_title', 'en', 'Licenses', CURRENT_TIMESTAMP),
  ('about_support_licenses_desc', 'en', 'The licenses page lists Aliolo''s commercial license first and then the bundled third-party package licenses.', CURRENT_TIMESTAMP)
